import{_ as i,C as d,o,c as n,a3 as a,b as s,w as t,a as c,E as l,a4 as p}from"./chunks/framework.aYYe0dfI.js";const q=JSON.parse('{"title":"Module provider","description":"The provider module encapsulates the network-layer logic specific to interacting with a single LLM provider, such as OpenAI. It owns the responsibility for reading provider-specific credentials (API keys and base URLs) from the environment, constructing well-formed request paths, and parsing JSON responses with contextual error reporting. The module also handles serialization of tool call arguments and validation of completion requests, ensuring that outgoing requests conform to the expected schema and structure before they reach the HTTP layer.","frontmatter":{"title":"Module provider","description":"The provider module encapsulates the network-layer logic specific to interacting with a single LLM provider, such as OpenAI. It owns the responsibility for reading provider-specific credentials (API keys and base URLs) from the environment, constructing well-formed request paths, and parsing JSON responses with contextual error reporting. The module also handles serialization of tool call arguments and validation of completion requests, ensuring that outgoing requests conform to the expected schema and structure before they reach the HTTP layer.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/provider/index.md","filePath":"en/clore/modules/provider/index.md"}'),h={name:"clore/modules/provider/index.md"};function u(m,e,f,g,v,b){const r=d("Mermaid");return o(),n("div",null,[e[1]||(e[1]=a('<h1 id="module-provider" tabindex="-1">Module <code>provider</code> <a class="header-anchor" href="#module-provider" aria-label="Permalink to &quot;Module `provider`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>provider</code> module encapsulates the network-layer logic specific to interacting with a single LLM provider, such as <code>OpenAI</code>. It owns the responsibility for reading provider-specific credentials (API keys and base <code>URLs</code>) from the environment, constructing well-formed request paths, and parsing JSON responses with contextual error reporting. The module also handles serialization of tool call arguments and validation of completion requests, ensuring that outgoing requests conform to the expected schema and structure before they reach the HTTP layer.</p><p>Public-facing entities exposed by this module include <code>read_credentials</code>, <code>append_url_path</code>, <code>parse_json_object</code>, <code>serialize_tool_arguments</code>, and <code>validate_completion_request</code>. These functions serve as the primary interface for configuring authentication, building provider-specific endpoint <code>URLs</code>, and validating the shape of completion requests and tool-related payloads. The module builds on the lower-level <code>http</code>, <code>protocol</code>, and <code>schema</code> modules to coordinate the credential discovery, request construction, and structural validation needed before dispatching an HTTP request to the provider&#39;s API.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../http/"><code>http</code></a></li><li><a href="./../protocol/"><code>protocol</code></a></li><li><a href="./../schema/"><code>schema</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../anthropic/"><code>anthropic</code></a></li><li><a href="./../openai/"><code>openai</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',9)),(o(),s(p,null,{default:t(()=>[l(r,{id:"mermaid-55",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22provider%22%5D%0A%20%20%20%20I0%5B%22http%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22protocol%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22schema%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-net-detail-credentialenv" tabindex="-1"><code>clore::net::detail::CredentialEnv</code> <a class="header-anchor" href="#clore-net-detail-credentialenv" aria-label="Permalink to &quot;`clore::net::detail::CredentialEnv`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:14</code></p><p>Definition: <code>network/provider.cppm:14</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The struct <code>clore::net::detail::CredentialEnv</code> is a lightweight aggregate that bundles two environment variable names as <code>std::string_view</code> members: <code>base_url_env</code> and <code>api_key_env</code>. It serves solely as a compile‑time or runtime container for the symbolic names of the environment variables that will be read to obtain provider connection parameters. The struct imposes no invariants beyond those inherent to <code>std::string_view</code> (i.e., the pointed‑to character sequences must outlive the view and remain valid). There are no user‑defined constructors, assignment <code>operator</code>s, or member functions; the type is a plain aggregate whose fields are intended to be accessed directly. This design keeps the credential environment specification trivially copyable and usable in <code>constexpr</code> or <code>static const</code> contexts where the underlying environment variable names are known at compile time.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Members are set to valid <code>std::string_view</code> objects.</li><li>No other invariants implied by the evidence.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>base_url_env</code></li><li><code>api_key_env</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Likely passed as a parameter to functions that read environment variables.</li><li>Used in the implementation of credential retrieval or connection setup.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-detail-append-url-path" tabindex="-1"><code>clore::net::detail::append_url_path</code> <a class="header-anchor" href="#clore-net-detail-append-url-path" aria-label="Permalink to &quot;`clore::net::detail::append_url_path`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:21</code></p><p>Definition: <code>network/provider.cppm:43</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The implementation of <code>clore::net::detail::append_url_path</code> follows a straightforward three‑step algorithm. First, it copies the input <code>base_url</code> into a local <code>std::string</code> and strips any trailing <code>&#39;/&#39;</code> characters using a <code>while</code> loop. Second, it copies the input <code>path</code> into a local <code>suffix</code> and removes any leading <code>&#39;/&#39;</code> characters via another <code>while</code> loop. Finally, if the trimmed <code>suffix</code> is not empty, it appends a single <code>&#39;/&#39;</code> and the <code>suffix</code> to the trimmed base URL. The function returns the resulting concatenated string. No external dependencies are required beyond the standard library’s string manipulation operations; the control flow consists solely of simple loops and a conditional guard.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>base_url</code> parameter</li><li><code>path</code> parameter</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>local <code>std::string url</code></li><li>local <code>std::string suffix</code></li><li>returned <code>std::string</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>URL path normalization before HTTP requests</li></ul><h3 id="clore-net-detail-parse-json-object" tabindex="-1"><code>clore::net::detail::parse_json_object</code> <a class="header-anchor" href="#clore-net-detail-parse-json-object" aria-label="Permalink to &quot;`clore::net::detail::parse_json_object`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:27</code></p><p>Definition: <code>network/provider.cppm:148</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The function attempts to parse the raw JSON string <code>raw</code> into a <code>json::Object</code> using <code>json::parse&lt;json::Object&gt;</code>. If parsing fails (the result has no value), it returns a <code>std::unexpected</code> containing an <code>LLMError</code> constructed with the context string and the parser’s error description. Otherwise, it returns the successfully parsed object by dereferencing the expected value.</p><p>The control flow is a single conditional branch after the parse attempt. Its only dependencies are the <code>json::parse</code> template (specialized for <code>json::Object</code>) and the <code>LLMError</code> type, which is used to wrap error information. The <code>context</code> parameter is used solely to prefix the error message, aiding in identification of the source of the parsing failure.</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>raw</code> parameter (<code>std::string_view</code>)</li><li><code>context</code> parameter (<code>std::string_view</code>)</li><li>global string literals for formatting (implied)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>parsing a JSON object from a raw response string</li><li>wrapping parse errors with contextual information</li></ul><h3 id="clore-net-detail-read-credentials" tabindex="-1"><code>clore::net::detail::read_credentials</code> <a class="header-anchor" href="#clore-net-detail-read-credentials" aria-label="Permalink to &quot;`clore::net::detail::read_credentials`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:19</code></p><p>Definition: <code>network/provider.cppm:39</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The function <code>clore::net::detail::read_credentials</code> is a thin delegation wrapper that extracts the two fields from its <code>CredentialEnv</code> parameter — <code>base_url_env</code> and <code>api_key_env</code> — and forwards them to <code>clore::net::detail::read_environment</code>. The underlying function is responsible for reading the actual environment variables identified by those names, parsing the values, and constructing the resulting <code>EnvironmentConfig</code> or returning an error. Consequently, the algorithm of <code>read_credentials</code> is purely structural: it unpacks the configuration struct, passes the two environment variable names (as <code>std::string_view</code> instances) to the core routine, and relays the outcome. Dependencies are limited to the <code>CredentialEnv</code> type and the <code>read_environment</code> function, along with the error type <code>LLMError</code>.</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads environment variables (I/O)</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>env<code>.base_url_env</code></li><li>env<code>.api_key_env</code></li><li>Environment variables named by these strings</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Return value (<code>std::expected&lt;EnvironmentConfig, LLMError&gt;</code>)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to load credentials from environment variables</li><li>Called during initialization of network connections</li></ul><h3 id="clore-net-detail-serialize-tool-arguments" tabindex="-1"><code>clore::net::detail::serialize_tool_arguments</code> <a class="header-anchor" href="#clore-net-detail-serialize-tool-arguments" aria-label="Permalink to &quot;`clore::net::detail::serialize_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:30</code></p><p>Definition: <code>network/provider.cppm:158</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The implementation of <code>clore::net::detail::serialize_tool_arguments</code> performs a round‑trip validation of the provided <code>json::Value</code> arguments. It first attempts to serialize <code>arguments</code> into a JSON string using <code>json::to_string</code>. If serialization fails, the function immediately returns an error constructed via <code>unexpected_json_error</code> using the supplied <code>context</code> and the error from <code>json::to_string</code>. On success, it re‑parses the resulting string back into a <code>json::Value</code> with <code>json::parse</code>. If parsing fails, it returns <code>std::unexpected</code> wrapping a <code>LLMError</code> that includes <code>context</code> and the parsing error. Otherwise, the function returns a <code>std::pair</code> containing both the serialized string form and the re‑parsed value, guaranteeing that the output JSON representation is valid and consistent.</p><p>The algorithm thus relies on the symmetry of serialization and parsing to detect malformed or unserializable JSON values early. Key dependencies include <code>json::to_string</code>, <code>json::parse</code>, and the error‑handling utilities <code>unexpected_json_error</code> and <code>LLMError</code>. The <code>context</code> parameter is used solely for enriching error messages, with no effect on the core control flow.</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>json::Value arguments</code></li><li><code>std::string_view context</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to re-serialize and validate tool arguments</li><li>Called when tool arguments need to be normalized or error-checked</li></ul><h3 id="clore-net-detail-validate-completion-request" tabindex="-1"><code>clore::net::detail::validate_completion_request</code> <a class="header-anchor" href="#clore-net-detail-validate-completion-request" aria-label="Permalink to &quot;`clore::net::detail::validate_completion_request`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:23</code></p><p>Definition: <code>network/provider.cppm:61</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>The function performs a series of preflight checks on the provided <code>CompletionRequest</code> before it is submitted to an upstream API. It first verifies that <code>request.model</code> and <code>request.messages</code> are non‑empty, returning <code>std::unexpected(LLMError(...))</code> if either condition fails. When <code>validate_response_format_schema</code> is <code>true</code> and <code>request.response_format</code> is present, the schema is validated via <code>validate_response_format</code>; similarly, when <code>validate_tool_schemas</code> is <code>true</code>, each element of <code>request.tools</code> is validated using <code>validate_tool_definition</code>. Additional cross‑field constraints are enforced: if <code>request.tool_choice</code> or <code>request.parallel_tool_calls</code> are set, at least one tool must be defined, and a <code>ForcedFunctionToolChoice</code> requires that its <code>name</code> exists among the provided tools.</p><p>The message payload is then inspected by iterating over <code>request.messages</code> and applying a <code>std::visit</code>‑based validator. For <code>AssistantToolCallMessage</code> entries, either <code>content</code> or at least one <code>tool_calls</code> must be present; each tool call must have non‑empty <code>id</code> and <code>name</code>, and all <code>id</code> values must be unique (enforced with a <code>std::unordered_set</code>). For <code>ToolResultMessage</code> entries, the <code>tool_call_id</code> must be non‑empty. Any validation failure causes an immediate <code>std::unexpected</code> return with a descriptive <code>LLMError</code>. The function returns an empty <code>std::expected&lt;void, LLMError&gt;</code> on success.</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>CompletionRequest</code> fields: <code>model</code>, <code>messages</code>, <code>response_format</code>, <code>tools</code>, <code>tool_choice</code>, <code>parallel_tool_calls</code></li><li>message fields: <code>content</code>, <code>tool_calls</code>, <code>tool_call_id</code>, <code>id</code>, <code>name</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called before initiating a completion request to validate the request structure</li><li>part of request validation pipeline</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The <code>provider</code> module is the network‑layer component responsible for orchestrating communication with a specific LLM provider. It decomposes provider‑specific concerns into a set of <code>detail</code>‑scoped utilities: <code>read_credentials</code> probes environment variables defined by <code>CredentialEnv</code> (which carries <code>base_url_env</code> and <code>api_key_env</code> names) to obtain authentication and endpoint configuration; <code>append_url_path</code> constructs clean URL paths from base and segment strings; <code>parse_json_object</code> attempts JSON‑object parsing with context‑aware error reporting; <code>serialize_tool_arguments</code> converts tool‑call argument JSON into a serialized form; and <code>validate_completion_request</code> performs structural validation of a completion request against boolean flags.</p><p>Imports reflect a three‑layer dependency: <code>std</code> for core language support, <code>http</code> for actual request dispatch and rate‑limiting, <code>protocol</code> for the request/response types (e.g., <code>CompletionRequest</code>, <code>ToolCall</code>), and <code>schema</code> for generating <code>OpenAI</code>‑compatible JSON schemas used in tool definitions and response format validation. Internally, <code>provider</code> uses variable‑scoped schemas (<code>validate_tool_schemas</code>, <code>validate_response_format_schema</code>) that are likely loaded once and reused across validation calls. The module does not own HTTP transport or protocol types; instead it composes them into a cohesive provider client that translates high‑level tool call and completion requests into properly authenticated, validated, and serialized network operations.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../http/">Module http</a></li><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../schema/">Module schema</a></li></ul>',80))])}const y=i(h,[["render",u]]);export{q as __pageData,y as default};
